'use client';

type Props = {
  lines?: number;
  className?: string;
};

export function SkeletonBlock({ lines = 3, className = '' }: Props) {
  return (
    <div className={`pc-skeleton pc-skeleton-card ${className}`.trim()} aria-hidden="true">
      {Array.from({ length: lines }, (_, i) => (
        <div key={i} className="pc-skeleton-line" />
      ))}
    </div>
  );
}
