'use client';

import type { ButtonHTMLAttributes, ReactNode } from 'react';

type Props = ButtonHTMLAttributes<HTMLButtonElement> & {
  children: ReactNode;
  variant?: 'primary' | 'secondary' | 'ghost';
  glow?: boolean;
};

export function InstantFeelButton({
  children,
  variant = 'primary',
  glow = false,
  className = '',
  type = 'button',
  ...rest
}: Props) {
  const variantClass =
    variant === 'secondary' ? 'pc-btn-secondary' : variant === 'ghost' ? 'pc-btn-ghost' : 'pc-btn-primary';

  return (
    <button
      type={type}
      className={`pc-btn pc-tap ${glow ? 'pc-tap-glow' : ''} ${variantClass} ${className}`.trim()}
      {...rest}
    >
      {children}
    </button>
  );
}
