'use client';

type Props = {
  label: string;
  className?: string;
};

/** Small momentum indicator — "something is happening" without blocking UI */
export function ProgressMomentum({ label, className = '' }: Props) {
  return (
    <span className={`pc-progress-chip ${className}`.trim()} role="status">
      {label}
    </span>
  );
}
